    34→    paymentTerms?: string;
    35→    vat?: number;
    36→  } | null;
    37→  errorMessage: string | null;
    38→  analyzedAt: string | null;
    39→}
    40→
    41→interface Offer {
    42→  id: string;
    43→  companyId: string;
    44→  technicalFileUrl: string | null;
    45→  financialFileUrl: string | null;
    46→  combinedFileUrl?: string | null;
    47→  quotePrice: number | null;
    48→  videoUrl: string | null;
    49→  submittedAt: string;
    50→  status: string;
    51→  company: {
    52→    id: string;
    53→    name: string;
    54→    category: string | null;
    55→    verificationStatus: string;
    56→  };
    57→  profile?: {
    58→    displayName: string | null;
