    62→}
    63→
    64→interface ProposalComparisonProps {
    65→  tenderId: string;
    66→  offers: Offer[];
    67→  analyses?: OfferAnalysis[];
    68→}
    69→
    70→export default function ProposalComparison({ tenderId, offers, analyses = [] }: ProposalComparisonProps) {
    71→  const { toast } = useToast();
    72→  const [hiddenOffers, setHiddenOffers] = useState<Set<string>>(new Set());
    73→  const [selectedVendor, setSelectedVendor] = useState<string | null>(null);
    74→
    75→  const analyzeMutation = useMutation({
    76→    mutationFn: async () => {
    77→      const response = await apiRequest("POST", `/api/ai/analyze-proposals/${tenderId}`);
    78→      return response.json();
    79→    },
    80→    onSuccess: () => {
    81→      queryClient.invalidateQueries({ queryKey: ["/api/ai/proposal-analysis", tenderId] });
    82→      toast({ title: "Analysis complete", description: "All proposals have been analyzed." });
    83→    },
    84→    onError: (error: Error) => {
    85→      toast({ title: "Analysis failed", description: error.message, variant: "destructive" });
    86→    },
    87→  });
    88→
    89→  const savingsMutation = useMutation({
    90→    mutationFn: async (data: any) => {
    91→      const response = await apiRequest("POST", `/api/tenders/${tenderId}/savings`, data);
    92→      return response.json();
    93→    },
    94→    onSuccess: (data) => {
    95→      toast({
    96→        title: "Vendor selected",
    97→        description: `Savings recorded: SAR ${data.savingsAmount?.toLocaleString() || 0} (${data.savingsPercentage || 0}% savings)`,
    98→      });
    99→    },
   100→    onError: (error: Error) => {
   101→      toast({ title: "Failed to record savings", description: error.message, variant: "destructive" });
   102→    },
   103→  });
   104→
   105→  // Get completed analyses matched to offers
   106→  const completedAnalyses = analyses.filter(a => a.status === "completed");
   107→  const hasAnalyses = completedAnalyses.length > 0;
   108→
   109→  // Filter visible offers
   110→  const visibleOffers = offers.filter(o => !hiddenOffers.has(o.id));
   111→  const removedOffers = offers.filter(o => hiddenOffers.has(o.id));
   112→
   113→  // Build deliverables union
   114→  const allDeliverables = new Set<string>();
   115→  completedAnalyses.forEach(a => {
   116→    if (a.deliverables) a.deliverables.forEach(d => allDeliverables.add(d));
   117→  });
   118→
   119→  // Financial data per offer
   120→  const getFinancial = (offerId: string) => {
   121→    const analysis = completedAnalyses.find(a => a.offerId === offerId);
   122→    return analysis?.financial || null;
   123→  };
   124→
   125→  const getTotal = (offerId: string): number | null => {
