   329→              <span className="text-sm text-green-800">
   330→                <span className="font-semibold">Potential savings:</span> SAR {(highestPrice - lowestPrice).toLocaleString()} between cheapest and most expensive offer
   331→              </span>
   332→            </div>
   333→          )}
   334→        </div>
   335→
   336→        {/* Section C: Actions per vendor */}
   337→        <div>
   338→          <h4 className="font-semibold text-sm text-gray-700 mb-3">Actions</h4>
   339→          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
   340→            {visibleOffers.map(o => (
   341→              <div key={o.id} className={`rounded-xl border p-4 space-y-3 ${selectedVendor === o.id ? 'border-blue-300 bg-blue-50/50' : 'border-gray-200'}`}>
   342→                <div className="flex items-center justify-between">
   343→                  <div>
   344→                    <p className="font-semibold text-sm text-gray-900">{getVendorName(o)}</p>
   345→                    {o.company.category && <p className="text-xs text-gray-400">{o.company.category}</p>}
   346→                  </div>
   347→                  {selectedVendor === o.id && (
   348→                    <Badge className="bg-blue-100 text-blue-700 text-xs">Selected</Badge>
   349→                  )}
