                      </div>
                    </div>
                  )}

                  {/* Deliverables */}
                  {drawerAnalysis.deliverables && drawerAnalysis.deliverables.length > 0 && (
                    <div>
                      <p className="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-2">Deliverables</p>
                      <ul className="space-y-1.5">
